  mutation DiscountCodeActivateNoopIdempotence($id: ID!) {
    discountCodeActivate(id: $id) {
      #graphql
  codeDiscountNode {
    id
    codeDiscount {
      __typename
      ... on DiscountCodeBasic {
        #graphql
  __typename
  startsAt
  endsAt
  status
  updatedAt

      }
    }
  }
  userErrors {
    field
    message
    code
    extraInfo
  }

    }
  }

