upstreamCalls.query:
#graphql
  query DiscountHydrate($id: ID!) {
    codeNode: codeDiscountNode(id: $id) {
      id
      codeDiscount {
        __typename
        ... on DiscountCodeBasic {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
          codes(first: 250) {
            nodes {
              id
              code
              asyncUsageCount
            }
          }
        }
        ... on DiscountCodeApp {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountCodeBxgy {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountCodeFreeShipping {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
      }
    }
    automaticNode: automaticDiscountNode(id: $id) {
      id
      automaticDiscount {
        __typename
        ... on DiscountAutomaticBasic {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountAutomaticApp {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountAutomaticBxgy {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
        ... on DiscountAutomaticFreeShipping {
          title
          status
          startsAt
          endsAt
          updatedAt
          asyncUsageCount
        }
      }
    }
  }

